Settings类决定哪些工程需要被gradle处理，Settings类通过settings.gradle配置文件来初始化 SourceSet类决定了代码、资源、第三方库要存放的位置。gradle约定大于配置，只要没有做修改，默认按照约定的来，默认从java文件夹下获取代码、从res文件夹下获取资源 修改SO文件位置sourceSets { main{ jniLibs.srcDirs = [&apos;libs&apos;] } } 修改资源文件夹this.android.sourceSets{ main{ res.srcDirs = [&apos;src/main/res&apos;, &apos;src/main/res-ad&apos;, &apos;src/main/res-player&apos;] } } Plugin及自定义Plugin完成特定任务的所有task都封装在某一个插件中，这样引入这个插件就可以完成特定的功能。 第一种方式直接在build.gradle文件中编写好处：自动编译，无需执行其他操作。 坏处：生成的插件，对外部是不可见的，只能在当前的功能下使用。 一般来说，不会使用这种方式。 第二种方式创建buildSrc的module目录如下 修改build.gradle //groovy library apply plugin: &apos;groovy&apos; dependencies { // gradle sdk implementation gradleApi() // groovy sdk implementation localGroovy() } sourceSets { main{ groovy{ srcDir &apos;src/main/groovy&apos; } resources{ srcDir &apos;src/main/resources&apos; } } } 创建groovy类 /** * 自定义插件 */ class GradleStudyPlugin implements Plugin&lt;Project&gt;{ /** * 插件被引入时要执行的方法 * @param project 引入当前插件的project */ @Override void apply(Project project) { println &apos;hello this &apos;+project.name } } 创建properties文件 implementation-class=com.yly.gradle.study.GradleStudyPlugin app moudle引用 apply plugin: &apos;com.yly.gradle.study&apos; 添加实际逻辑 创建属性 /** * 与自定义PLugin进行参数传递 */ class ReleaseInfoExtension { String versionCode String versionName String versionInfo String fileName ReleaseInfoExtension() { } @Override String toString() { &quot;&quot;&quot;| versionCode = ${versionCode} | versionName = ${versionName} | versionInfo = ${versionInfo} | fileName = ${fileName} &quot;&quot;&quot;.stripMargin() } } apply方法中创建扩展属性 project.extensions.create(&apos;ylyReleaseInfo&apos;, ReleaseInfoExtension) app moudle为自定义插件传递参数 ylyReleaseInfo{ versionCode = rootProject.ext.android.versionCode versionName = rootProject.ext.android.versionName versionInfo = &apos;第8个版本。。。&apos; fileName = &apos;releases.xml&apos; } 创建自定义Task /** * 自定义Task,实现维护版本信息功能 */ class ReleaseInfoTask extends DefaultTask{ ReleaseInfoTask() { group = &apos;yly&apos; description = &apos;update the release info&apos; } /** * 执行于gradle执行阶段的代码 * TaskAction注解的方法执行于执行阶段，doFirst为它之前，doLast为它之后 */ @TaskAction void doAction() { updateInfo() } //真正的将Extension类中的信息呢，写入指定文件中 private void updateInfo() { //获取将要写入的信息 String versionCodeMsg = project.extensions. ylyReleaseInfo.versionCode String versionNameMsg = project.extensions. ylyReleaseInfo.versionName String versionInfoMsg = project.extensions. ylyReleaseInfo.versionInfo String fileName = project.extensions. ylyReleaseInfo.fileName def file = project.file(fileName) //将实体对象写入到xml文件中 def sw = new StringWriter() def xmlBuilder = new MarkupBuilder(sw) if (file.text != null &amp;&amp; file.text.size() &lt;= 0) { //没有内容 xmlBuilder.releases { release { versionCode(versionCodeMsg) versionName(versionNameMsg) versionInfo(versionInfoMsg) } } //直接写入 file.withWriter { writer -&gt; writer.append(sw.toString()) } } else { //已有其它版本内容 xmlBuilder.release { versionCode(versionCodeMsg) versionName(versionNameMsg) versionInfo(versionInfoMsg) } //插入到最后一行前面 def lines = file.readLines() def lengths = lines.size() - 1 file.withWriter { writer -&gt; lines.eachWithIndex { line, index -&gt; if (index != lengths) { writer.append(line + &apos;
&apos;) } else if (index == lengths) { writer.append(&apos;
&apos; + sw.toString() + &apos;
&apos;) writer.append(lines.get(lengths)) } } } } } } apply方法中创建Task project.tasks.create(&apos;ylyReleaseInfoTask&apos;, ReleaseInfoTask) 执行task ./gradlew ylyReleaseInfoTask 缺点：只对当前工程可用 第三种方式Standalone project优点：插件的module名字，可以随意。这种方式，就是将我们写的一些插件，任务等等打包到一起，生成jar，通过jar包的方式使用。所以， 在其他的项目也是可以使用的 参考文档 Android及Java插件对gradle的扩展Android扩展Android可以配置的属性（为每个变体配置） Android引入的task，在每个变体中获取相应的task 参考文档 this.afterEvaluate { //获取所有变体并遍历 this.android.applicationVariants.all { variant-&gt; def name = variant.name def baseName = variant.baseName println &quot;name is ${name},baseName is ${baseName}&quot; } } 改变输出apk名称，修改变体中的属性 this.afterEvaluate { //获取所有变体并遍历 this.android.applicationVariants.all { variant-&gt; def output = variant.outputs.first() def apkName = &quot;app-${variant.baseName}&quot; + &quot;-${variant.versionName}.apk&quot; output.outputFileName = apkName println output.outputFileName } } 获取变体中的task，后续可以进行操作 this.afterEvaluate { //获取所有变体并遍历 this.android.applicationVariants.all { variant-&gt; //修改变体中的task def task = variant.checkManifest println task.name } } 实际案例，壳工程下载包含的最新子工程 /** * 创建时间：2017年12月22日 &lt;br&gt; * 作者：renzhiqiang &lt;br&gt; * 描述：插件自动更新脚本 * 流程描述： 1、解析插件配置 * 2、请求该配置下的最新版本 * 3、检验本地是否存在相同配置的版本 * 4、ipackage下载插件 * 5、校验下载的文件的合法性 */ import groovy.json.JsonSlurper import java.security.MessageDigest /** * 入口 */ this.afterEvaluate { this.android.applicationVariants.all { variant -&gt; def checkTask = variant.checkManifest checkTask.doFirst { def bt = variant.buildType.name if (bt.equals(&apos;qa&apos;) || bt.equals(&apos;preview&apos;) || bt.equals(&apos;release&apos;)) { update_plugin(bt) } } } } /** * 1.读取配置文件 * 2.根据配置生成获取插件下载地址的url * 3.拼接下载地址，插件文件名，插件md5文件名成string * @param buildType 打包的buildType */ def update_plugin(String buildType) { //使用线上配置 def config = getJsonDataFromNet(rootProject.ext.android.pluginConfigUrl); println &apos;plugin config is :&apos; + config + &quot; 
count=&quot; + config.size() def pluginUrl = &apos;http://i.package.imooc.com/api/package/search.json&apos; int pluginSize = config.size() for (int i = 0; i &lt; pluginSize; i++) { def plugin = config[i] println(&quot;1、解析&quot; + plugin.projectname + &quot;的插件配置&quot;) println(plugin.projectname + &quot;插件配置为：&quot; + plugin) StringBuilder urlRequest = new StringBuilder(pluginUrl) urlRequest.append(&apos;?&apos;) urlRequest.append(&apos;project=&apos;).append(plugin.projectname).append(&apos;&amp;&apos;) urlRequest.append(&apos;version=&apos;).append(plugin.version).append(&apos;&amp;&apos;) if (plugin.type != null) { urlRequest.append(&apos;type=&apos;).append(plugin.type) if (plugin.commit_hash != null) { urlRequest.append(&apos;&amp;&apos;) urlRequest.append(&apos;commit_hash=&apos;).append(plugin.commit_hash) } else { if (plugin.type == &apos;release&apos;) { //release时必须有commitHash否则直接返回失败 // return false } } } else { if (buildType.equals(&apos;qa&apos;)) { urlRequest.append(&apos;type=&apos;).append(&apos;debug&apos;) if (plugin.commit_hash != null) { urlRequest.append(&apos;&amp;&apos;) urlRequest.append(&apos;commit_hash=&apos;).append(plugin.commit_hash) } } else if (buildType.equals(&apos;release&apos;)) { //release时必须有commitHash否则直接返回失败 if (plugin.commit_hash == null) { // return false } else { urlRequest.append(&apos;type=&apos;).append(&apos;release&apos;).append(&apos;&amp;&apos;) urlRequest.append(&apos;commit_hash=&apos;).append(plugin.commit_hash) } } else if (buildType.equals(&apos;preview&apos;)) { //preview时必须有commitHash否则直接返回失败 if (plugin.commit_hash == null) { // return false } else { urlRequest.append(&apos;type=&apos;).append(&apos;preview&apos;).append(&apos;&amp;&apos;) urlRequest.append(&apos;commit_hash=&apos;).append(plugin.commit_hash) } } } def success = askForLatest(urlRequest.toString(), plugin.jar_name, plugin.jar_md5_name) if (success) { println &apos;-----------&apos; + plugin.jar_name + &apos; update successfull-----&apos; println() } else { println &apos;-----------&apos; + plugin.jar_name + &apos; update failed-----&apos; println() throw new IllegalArgumentException(plugin.jar_name + &apos; update failed !!!!!&apos;) } } } /** * 获取插件最新版本 * 1、根据版本配置请求ipackage上该插件的所有文件（一个配置会有多个插件文件） * 2、下载最新一个文件（约定第一个为最新） * @param url * @param jarname * @param jarMd5name * @return */ def askForLatest(String url, String jarname, String jarMd5name) { println(&quot;2、从ipackage请求该配置下的最新版本&quot;) println(&quot;请求链接为：&quot; + url) def pluginList = getJsonDataFromNet(url).result if (pluginList.size() &gt; 0) { def latestPlugin = pluginList[0] println(&quot;搜索最新版本成功：&quot; + latestPlugin) if (isPluginExist(jarname, jarMd5name, latestPlugin.md5)) { return true; } else { def flag = down(latestPlugin.download_url, jarname) if (flag) { flag = checkMd5(jarname, latestPlugin.md5) } return flag } } else { println(&quot;搜索最新版本失败，更新插件失败&quot;) return false } } /** * 校验本地是否已经存在符合配置的插件 * 1、校验插件文件是否存在 * 2、校验插件md5文件是否存在以及内容是否一致 * 3、1和2同时满足即为符合否则删除该插件的相关文件 * @param jarname * @param jarMd5name * @param md5 * @return */ def isPluginExist(String jarname, String jarMd5name, String md5) { println(&quot;3、检验本地是否存在相同配置的版本&quot;) println(&quot;检验条件：&quot; + &quot;文件名&quot; + jarname + &quot;，md5值&quot; + md5) String pluginPath = &apos;src/main/assets/plugins/&apos; File pluginfile; File md5file; String md5content; FileCollection plugins = files { file(pluginPath).listFiles() } plugins.each { File file -&gt; if (file.getName().equals(jarname)) { pluginfile = file; } if (file.getName().equals(jarMd5name)) { md5file = file; md5content = getFileContent(file); } } if (pluginfile != null &amp;&amp; md5content.equals(md5)) { println(&quot;本地存在相同配置的版本，跳过下载，返回成功&quot;) return true; } //本地的不匹配则删除 if (pluginfile != null) { pluginfile.delete() } if (md5file != null) { md5file.delete() } println(&quot;本地不存在相同配置的版本&quot;) return false } /** * 下载网络文件 * @param url * @param jarname * @return */ def down(String url, String jarname) { println(&quot;4、开始ipackage下载&quot;) println(&quot;下载url为：&quot; + url) def file = new File(project.getProjectDir().getAbsolutePath() + &quot;/src/main/assets/plugins/&quot; + jarname) InputStream is FileOutputStream fos try { def connection = new URL(url).openConnection() connection.setRequestMethod(&apos;GET&apos;) connection.connect() is = connection.getInputStream() fos = new FileOutputStream(file) byte[] b = new byte[1024] int len = 0 while ((len = is.read(b)) != -1) { fos.write(b, 0, len) } fos.flush() println(&quot;文件下载成功&quot;) return true } catch (Exception e) { println(&quot;文件下载失败&quot;) println(e.printStackTrace()) return false } finally { if (fos != null) { fos.close() } if (is != null) { is.close() } } } /** * 下载成功后校验文件与返回的md5是否匹配 * 不匹配则删除文件 * @param jarname * @param md5 * @return */ def checkMd5(String jarname, String md5) { println(&quot;5、开始校验下载的文件的合法性&quot;) // println(&quot;ipackage返回的md5 = &quot; + md5) String pluginPath = &apos;src/main/assets/plugins/&apos; FileCollection plugins = files { file(pluginPath).listFiles() } plugins.each { File file -&gt; if (file.getName().equals(jarname)) { def digest = MessageDigest.getInstance(&quot;MD5&quot;).digest(file.bytes).encodeHex().toString() // println(&quot;下载后计算的md5 = &quot; + digest) if (digest.equals(md5)) { File md5File = new File(pluginPath + file.name + &apos;.md5&apos;) FileCollection collectionss = files(md5File) collectionss.getFiles().getAt(0).withWriter(&apos;UTF-8&apos;) { within -&gt; within.append(digest) } println(&quot;md5校验成功&quot;) return true; } else { file.delete() println(&quot;md5校验失败，删除已下载文件&quot;) return false; } } } } /** * 获取文件的第一行 * md5文件只有一行 * @param file * @return */ def getFileContent(File file) { List&lt;String&gt; contents = file.readLines(); if (contents != null &amp;&amp; contents.size() &gt; 0) { return contents.get(0); } return &quot;&quot;; } /** * 从网络获取json数据 * @param url * @return */ def getJsonDataFromNet(String url) { //使用接口配置 def connection = new URL(url).openConnection() connection.setRequestMethod(&apos;GET&apos;) connection.connect() def resp = connection.content.text def jsonSlurper = new JsonSlurper() return jsonSlurper.parseText(resp).data } //关闭测试相关的task tasks.whenTaskAdded { task -&gt; if (task.name.contains(&apos;AndroidTest&apos;)) { task.enabled = false } } Java扩展没有变体的概念 官方文档 如何迁移到gradle 迁移 通过创建gradle文件，修改sourceSets 改造资源文件夹、代码文件夹、构建脚本位置，将这三部分移动到gradle对应的目录下。 新建一个gradle工程，将老工程对应的东西移过来。推荐这种方式。 总结 Gradle及其生命周期 Project相关概念及方法 Task创建，执行及依赖 Setting、SourceSet等其他模块类讲解 Android/Java插件对gradle的扩展 自定义Plugin讲解及实战
